SELECT COUNT(fight_id) AS total_fights
FROM fight_stats
WHERE fighter_id = 1;

SELECT COUNT(*) AS fighter_count
FROM fighters
WHERE weight_class = 'Welterweight';

SELECT fighter_name
FROM fighters
WHERE team = 'Tristar Gym';

SELECT COUNT(fight_id) AS total_fights
FROM fights
WHERE fighter_1_id = 1 OR fighter_2_id = 1;

SELECT fighter_name, total_wins
FROM fighters
ORDER BY total_wins DESC;

SELECT total_wins
FROM fighters
WHERE fighter_id = 1;

SELECT fighter_1_id AS fighter_id, COUNT(fight_id) AS total_fights
FROM fights
GROUP BY fighter_1_id;

SELECT fighter_name
FROM fighters
WHERE dob = (SELECT MIN(dob) FROM fighters);

SELECT weight_class, COUNT(*) AS fighter_count
FROM fighters
GROUP BY weight_class;

SELECT fighter_name, total_wins
FROM fighters
ORDER BY total_wins DESC;

SELECT fighter_name, total_wins
FROM fighters
ORDER BY total_wins DESC;
